        tid: Tid,
        pid: Pid,
        trap_cx: TrapContext,
    ) -> Self {
        let kernel_stack = KernelStack::new();

        let trap_cx_ptr = unsafe {
            kernel_stack.push_context(trap_cx)
        };

        let task_cx = TaskContext::goto_task_entry(trap_cx_ptr as usize);

        Self {
            tid,
            pid,

