pub struct TaskManager {
    processes: Vec<Option<ProcessControlBlock>>,
    threads: Vec<Option<ThreadControlBlock>>,

    free_pids: Vec<Pid>,
    free_tids: Vec<Tid>,

    sched_alpha: isize,

    scale_cache: Vec<usize>,
    cache_alpha: isize,
}

pub enum WaitPidAction {
    Return(isize),
    Block,
}

pub enum JoinAction {
