pub struct TmpfsFile {
    data: Arc<Mutex<Vec<u8>>>,
    offset: Mutex<usize>,  
    flags: usize,  
}

impl File for TmpfsFile {
    fn readable(&self) -> bool {
        let access = self.flags & O_ACCMODE;     
        access == O_RDONLY || access == O_RDWR
    }

    fn writable(&self) -> bool {
        let access = self.flags& O_ACCMODE;
        access == O_WRONLY || access == O_RDWR
    }

    fn read(&self, buf: &mut [u8]) -> isize {
        let data = self.data.lock();
        let mut off = self.offset.lock();
        let mut n = 0;
        while *off < data.len() && n < buf.len() {
            buf[n] = data[*off];
            *off += 1;
            n += 1;
        }
        n as isize
    }

    fn write(&self, buf: &[u8]) -> isize {
        let mut data = self.data.lock();
        let mut off = self.offset.lock();
        if self.is_append() {
            *off = data.len(); 
        }
        for &b in buf {
            if *off < data.len() {
                data[*off] = b;       
            } else {
                data.push(b);         
            }
            *off += 1;
        }
        buf.len() as isize
    }

    fn stat(&self) -> Stat {
        Stat::new(STAT_TYPE_FILE, self.data.lock().len())
    }

}


impl TmpfsFile {
    pub fn new(data: Arc<Mutex<Vec<u8>>>,flags : usize) -> Self {
        TmpfsFile {
            data,                         
            offset: Mutex::new(0),
            flags: flags,
        }
    }

    pub fn is_append(&self) -> bool {
        return (self.flags | O_APPEND) != 0;
    }
}

