pub trait FileSystem: Send + Sync {
    fn root_inode(self: Arc<Self>) -> InodeRef;
}

pub struct Mount {
    mount_point : String,
    fs : Arc<dyn FileSystem>,
}

static MOUNTS: Mutex<Vec<Mount>> = Mutex::new(Vec::new());


pub fn mount(mount_point: &str, fs: Arc<dyn FileSystem>) {
    let mut mounts = MOUNTS.lock();
    mounts.push(Mount {
        mount_point: String::from(mount_point),
        fs,
    });
}


pub fn resolve_mount(abs_path: &str) -> Option<(InodeRef, String)> {
    let mounts = MOUNTS.lock();

    let mut best: Option<&Mount> = None;

    for m in mounts.iter() {
        if path_under(abs_path, &m.mount_point) {

            match best {
                None => best = Some(m),
                Some(b) if m.mount_point.len() > b.mount_point.len() => best = Some(m),
                _ => {}
            }
        }
    }

    let m = best?;
    let root = m.fs.clone().root_inode();
    let rel = relative_path(abs_path, &m.mount_point);
    Some((root, rel))
}

fn path_under(abs_path: &str, mount_point: &str) -> bool {
    if mount_point == "/" {
        return true;  
    }
    if abs_path == mount_point {
        return true; 
    }
    abs_path.starts_with(mount_point)
        && abs_path.as_bytes().get(mount_point.len()) == Some(&b'/')
}


fn relative_path(abs_path: &str, mount_point: &str) -> String {
    if mount_point == "/" {
        return String::from(abs_path.trim_start_matches('/'));
    }
    let rest = &abs_path[mount_point.len()..];
    String::from(rest.trim_start_matches('/'))
}

use alloc::string::String;
use alloc::vec::Vec;

use super::inode::InodeRef;

pub fn normalize_path(cwd: &str, path: &str) -> Option<String> {
    let path = path.trim();

    if path.is_empty() {
        return None;
    }

    let mut parts: Vec<&str> = Vec::new();

    /*
     * 绝对路径从 / 开始。
     * 相对路径从 cwd 开始。
     */
    if !path.starts_with('/') {
        for part in cwd.split('/') {
            if part.is_empty() || part == "." {
                continue;
            }
            if part == ".." {
                parts.pop();
            } else {
                parts.push(part);
            }
        }
    }

    for part in path.split('/') {
        if part.is_empty() || part == "." {
            continue;
        }

        if part == ".." {
            parts.pop();
        } else {
            parts.push(part);
        }
    }

    let mut out = String::new();
    out.push('/');

    for (i, part) in parts.iter().enumerate() {
        if i > 0 {
            out.push('/');
        }
        out.push_str(part);
    }

    Some(out)
}

pub fn lookup_abs_path(path: &str) -> Option<InodeRef> {
    let path = normalize_path("/", path)?;

    let (mut current, rel) = crate::fs::mount::resolve_mount(&path)?;

    for part in rel.split('/') {
        if part.is_empty() {
            continue;
        }
        current = current.lookup(part)?;
    }
    Some(current)
}

pub fn lookup_path_at(cwd: &str, path: &str) -> Option<InodeRef> {
    let abs = normalize_path(cwd, path)?;
    lookup_abs_path(&abs)
}

use core::isize;

use crate::sync::spin::Mutex;
use crate::task::{block_current_on_pipe_read,block_current_on_pipe_write};
use crate::task::{wake_pipe_writers,wake_pipe_readers};

pub const PIPE_BUF_SIZE: usize = 512;

pub struct Pipe {
    pub buf: [u8; PIPE_BUF_SIZE], 
    pub head: usize,
    pub tail: usize,
    pub len: usize,
    pub writer_count: usize,
    pub reader_count: usize,
}

impl Pipe {
    pub fn new() -> Self{
        Pipe {
            buf: [0u8; PIPE_BUF_SIZE],
            head: 0,
            tail: 0,
            len: 0,
            writer_count: 1,
            reader_count: 1,
        }
    }
}

pub struct PipeReadEnd  { pub inner: Arc<Mutex<Pipe>> }
pub struct PipeWriteEnd { pub inner: Arc<Mutex<Pipe>> }

use alloc::sync::Arc;

use super::file::{File, FileRef,PipeCloseKind};
use super::stat::*;


impl File for PipeReadEnd {
    fn readable(&self) -> bool {
        true
    }

    fn writable(&self) -> bool {
        false
    }

    fn on_fork(&self){
        self.inner.lock().reader_count += 1;
    }

    fn on_close_kind(&self) -> super::file::PipeCloseKind {
        let mut pipe = self.inner.lock();
        pipe.reader_count -= 1;
        if pipe.reader_count == 0 { PipeCloseKind:: ReaderGone }
        else { PipeCloseKind::Nothing }
    }

    fn stat(&self) -> Stat {
        Stat::new(STAT_TYPE_PIPE, 0)
    }

    fn read(&self, buf: &mut [u8]) -> isize {
        loop{
            let mut pipe = self.inner.lock();
            if pipe.len != 0 {
                let mut count = 0;
                while count < buf.len() && pipe.len > 0 {
                    buf[count] = pipe.buf[pipe.head];
                    pipe.head = (pipe.head + 1) % PIPE_BUF_SIZE;
                    pipe.len -= 1;
                    count += 1;
                }
                drop(pipe);       
                wake_pipe_writers();
                return count as isize;
            }
            if pipe.writer_count <= 0 {
                return super::EOF;
            }
            drop(pipe);              
            block_current_on_pipe_read();
        }
    }
    fn write(&self, _buf: &[u8]) -> isize {
        -1
    }
}


impl File for PipeWriteEnd {
    fn readable(&self) -> bool {
        false
    }

    fn writable(&self) -> bool {
        true
    }

    fn on_fork(&self){
        self.inner.lock().writer_count += 1;
    }

    fn on_close_kind(&self) -> super::file::PipeCloseKind {
        let mut pipe = self.inner.lock();
        pipe.writer_count -= 1;
        if pipe.writer_count == 0 { PipeCloseKind::WriterGone }
        else { PipeCloseKind::Nothing }
    }

    fn stat(&self) -> Stat {
        Stat::new(STAT_TYPE_PIPE, 0)
    }

    fn read(&self, _buf: &mut [u8]) -> isize {
        -1
    }

    fn write(&self, buf: &[u8]) -> isize {
        loop{
            let mut pipe = self.inner.lock();
            if pipe.len != PIPE_BUF_SIZE {
                let mut count = 0;
                while count < buf.len() && pipe.len < PIPE_BUF_SIZE {
                    let tail = pipe.tail;    
                    pipe.buf[tail] = buf[count];
                    pipe.tail = (pipe.tail + 1) % PIPE_BUF_SIZE;
                    pipe.len += 1;
                    count += 1;
                }
                drop(pipe);       
                wake_pipe_readers();
                return count as isize;
            }
            if pipe.reader_count == 0 {
                return super::EPIPE;
            }
            drop(pipe);              
            block_current_on_pipe_write();
        }
    }
}

pub fn make_pipe() -> (FileRef, FileRef){
    let inner = Arc::new(Mutex::new(Pipe::new()));
    (Arc::new(PipeReadEnd{inner : inner.clone()}),Arc::new(PipeWriteEnd{inner : inner.clone()}))
}

