fn read_unaligned<T: Copy>(data: &[u8], offset: usize) -> Option<T> {
    if offset.checked_add(size_of::<T>())? > data.len() {
        return None;
    }

    Some(unsafe {
        core::ptr::read_unaligned(data.as_ptr().add(offset) as *const T)
    })
}

impl Elf64Header {
    pub fn parse(data: &[u8]) -> Option<Self> {
        let header: Self = read_unaligned(data, 0)?;

        if &header.ident[0..4] != ELF_MAGIC {
            return None;
        }

        if header.ident[4] != ELF_CLASS_64 {
            return None;
        }

        if header.ident[5] != ELF_DATA_LSB {
            return None;
        }

        if header.ident[6] != ELF_VERSION_CURRENT {
            return None;
        }

        if header.e_machine != ELF_MACHINE {
            return None;
        }

        if header.e_version != 1 {
            return None;
        }


        if header.e_type != ET_EXEC {
            return None;
        }

        if header.e_phentsize as usize != size_of::<Elf64ProgramHeader>() {
            return None;
        }

        Some(header)
    }

    pub fn program_header(&self, data: &[u8], index: usize) -> Option<Elf64ProgramHeader> {
        if index >= self.e_phnum as usize {
            return None;
        }

        let offset = (self.e_phoff as usize)
            .checked_add(index.checked_mul(self.e_phentsize as usize)?)?;

        read_unaligned(data, offset)
    }
}

//! LoongArch64 trap handling.
//!
//! This is a kernel bring-up trap framework, not rCore's batch-app framework.
//! It does not call run_next_app(); unsupported traps are logged and then panic.

mod context;

use core::arch::{asm, global_asm};
use core::fmt::{self, Write};

pub use context::TrapContext;

global_asm!(include_str!("trap.S"));
global_asm!(include_str!("tlb_refill.S"));


const ECODE_INT: usize = 0x00;
const ECODE_PIL: usize = 0x01;
const ECODE_PIS: usize = 0x02;
const ECODE_PIF: usize = 0x03;
const ECODE_PME: usize = 0x04;
const ECODE_PNR: usize = 0x05;
const ECODE_PNX: usize = 0x06;
const ECODE_PPI: usize = 0x07;
const ECODE_ADEF_ADEM: usize = 0x08;
const ECODE_ALE: usize = 0x09;
const ECODE_SYS: usize = 0x0b;
const ECODE_BRK: usize = 0x0c;
const ECODE_INE: usize = 0x0d;
const ECODE_IPE: usize = 0x0e;

const ESTAT_IS_TIMER: usize = 1 << 11;

macro_rules! trap_println {
    ($($arg:tt)*) => {{
        let _ = trap_log(format_args!($($arg)*));
    }};
}

fn trap_log(args: fmt::Arguments<'_>) -> fmt::Result {
    crate::io::console::_trap_log(args);
    Ok(())
}

pub fn init() {
    unsafe extern "C" {
        fn __alltraps();
    }

    let eentry = __alltraps as usize;

    unsafe {
        core::arch::asm!(
            "csrwr {0}, 0xc",
            in(reg) eentry,
            options(nostack)
        );
    }
    unsafe {
        core::arch::asm!(
            "csrwr $zero, 0x30",
            "csrwr $zero, 0x31",
            "csrwr $zero, 0x32",
            options(nostack)
        );
    }

    log::info!("LoongArch trap initialized: eentry={:#x}", eentry);
}



#[no_mangle]
pub extern "C" fn loongarch_trap_handler(cx: &mut TrapContext) -> &mut TrapContext {

    match cx.ecode() {
        ECODE_INT => handle_interrupt(cx),
        ECODE_SYS => {
            cx.era += 4;
            let syscall_id = cx.r[11]; // a7
            let args = [cx.r[4], cx.r[5], cx.r[6], cx.r[7], cx.r[8], cx.r[9]]; // a0, a1, a2
            cx.r[4] = handle_syscall(syscall_id, args) as usize; // return in a0
        }
        ECODE_BRK => {
            trap_println!("[trap] breakpoint at era={:#x}", cx.era);
            cx.era += 4;
        }

        ECODE_PIL
        | ECODE_PIS
        | ECODE_PIF
        | ECODE_PME
        | ECODE_PNR
        | ECODE_PNX
        | ECODE_PPI
        | ECODE_ADEF_ADEM
        | ECODE_ALE
        | ECODE_INE
        | ECODE_IPE => {
            trap_println!(
                "[trap] fatal exception: ecode={:#x}, esubcode={:#x}, era={:#x}, badv={:#x}, estat={:#x}",
                cx.ecode(),
                cx.esubcode(),
                cx.era,
                cx.badv,
                cx.estat
            );
            panic!("fatal LoongArch exception");
        }
        _ => {
            trap_println!(
                "[trap] unsupported exception: ecode={:#x}, esubcode={:#x}, era={:#x}, badv={:#x}, estat={:#x}",
                cx.ecode(),
                cx.esubcode(),
                cx.era,
                cx.badv,
                cx.estat
            );
            panic!("unsupported LoongArch exception");
        }
    }

    cx
}

fn handle_interrupt(cx: &mut TrapContext) {
    let pending = cx.interrupt_pending_bits();

    if pending & ESTAT_IS_TIMER != 0 {
        let should_schedule = crate::timer::tick();

        if should_schedule && cx.is_from_user() {
            crate::task::preempt_current_and_run_next();
        }
        if cx.is_from_user() {
            crate::task::account_current_tick();
        }

        return;
    }


    trap_println!(
        "[trap] unsupported interrupt: pending={:#x}, era={:#x}, estat={:#x}",
        pending,
        cx.era,
        cx.estat
    );
    panic!("unsupported LoongArch interrupt");
}

use alloc::sync::Arc;
use crate::block::BlockDevice;
use fatfs::{IoBase, Read, Write, Seek, SeekFrom};

const SECTOR_SIZE: usize = 512;

pub struct BlockIo {
    dev: Arc<dyn BlockDevice>,
    position: u64,
    size: u64,
}

impl BlockIo {
    pub fn new(dev: Arc<dyn BlockDevice>, num_sectors: u64) -> Self {
        Self {
            dev,
            position: 0,
            size: num_sectors * SECTOR_SIZE as u64,
        }
    }
}

impl IoBase for BlockIo {
    type Error = ();      // 直接用 () —— fatfs 已为 () 实现了 IoError
}

impl Read for BlockIo {
    fn read(&mut self, buf: &mut [u8]) -> Result<usize, ()> {
        if self.position >= self.size {
            return Ok(0);   // EOF
        }

        let remaining = (self.size - self.position) as usize;
        let to_read = buf.len().min(remaining);
        if to_read == 0 {
            return Ok(0);
        }

        let mut done = 0;
        let mut sector_buf = [0u8; SECTOR_SIZE];

        while done < to_read {
            let abs = self.position + done as u64;
            let sector = (abs / SECTOR_SIZE as u64) as usize;
            let off = (abs % SECTOR_SIZE as u64) as usize;

            if self.dev.read_block(sector, &mut sector_buf) != SECTOR_SIZE as isize {
                return Err(());
            }

            let chunk = (SECTOR_SIZE - off).min(to_read - done);
            buf[done..done + chunk].copy_from_slice(&sector_buf[off..off + chunk]);
            done += chunk;
        }

        self.position += done as u64;
        Ok(done)
    }
}

impl Write for BlockIo {
    fn write(&mut self, buf: &[u8]) -> Result<usize, ()> {
        if self.position >= self.size {
            return Ok(0);
        }

        let remaining = (self.size - self.position) as usize;
        let to_write = buf.len().min(remaining);
        if to_write == 0 {
            return Ok(0);
        }

        let mut done = 0;
        let mut sector_buf = [0u8; SECTOR_SIZE];

        while done < to_write {
            let abs = self.position + done as u64;
            let sector = (abs / SECTOR_SIZE as u64) as usize;
            let off = (abs % SECTOR_SIZE as u64) as usize;

            let chunk = (SECTOR_SIZE - off).min(to_write - done);

            if chunk == SECTOR_SIZE {
                // 整扇区写,直接覆盖
                sector_buf.copy_from_slice(&buf[done..done + chunk]);
            } else {
                // 非对齐:read-modify-write
                if self.dev.read_block(sector, &mut sector_buf) != SECTOR_SIZE as isize {
                    return Err(());
                }
                sector_buf[off..off + chunk].copy_from_slice(&buf[done..done + chunk]);
            }

            if self.dev.write_block(sector, &sector_buf) != SECTOR_SIZE as isize {
                return Err(());
            }

            done += chunk;
        }

        self.position += done as u64;
        Ok(done)
    }

    fn flush(&mut self) -> Result<(), ()> {
        Ok(())   // 无写缓存,每次 write 直接落盘
    }
}

impl Seek for BlockIo {
    fn seek(&mut self, pos: SeekFrom) -> Result<u64, ()> {
        let new_pos = match pos {
            SeekFrom::Start(n) => n as i64,
            SeekFrom::End(n) => self.size as i64 + n,
            SeekFrom::Current(n) => self.position as i64 + n,
        };

        if new_pos < 0 {
            return Err(());
        }

        self.position = new_pos as u64;
        Ok(self.position)
    }
}

